import{_ as i,o as e,c as a,a3 as n}from"./chunks/framework.d0TBG0Rg.js";const g=JSON.parse('{"title":"Mizuki Sync (已废弃)","description":"MizukiSync 舞萌 DX Android 查分工具，已停止维护。","frontmatter":{"title":"Mizuki Sync (已废弃)","description":"MizukiSync 舞萌 DX Android 查分工具，已停止维护。"},"headers":[],"relativePath":"projects/mizuki-sync.md","filePath":"projects/mizuki-sync.md"}'),r={name:"projects/mizuki-sync.md"};function o(l,t,s,d,c,u){return e(),a("div",null,[...t[0]||(t[0]=[n('<h1 id="mizuki-sync-舞萌同步-—-已废弃" tabindex="-1">Mizuki Sync (舞萌同步) — 已废弃 <a class="header-anchor" href="#mizuki-sync-舞萌同步-—-已废弃" aria-label="Permalink to &quot;Mizuki Sync (舞萌同步) — 已废弃&quot;">​</a></h1><div class="danger custom-block"><p class="custom-block-title">🛑 项目废弃声明</p><p>本项目已正式停止维护，不再提供任何更新和技术支持。以下内容仅作历史存档。</p></div><blockquote><p>MizukiSync 是一款专为舞萌 DX (maimai DX) 玩家设计的 Android 第三方客户端，通过对接落雪查分器 (LXNS) API，为玩家提供流畅的成绩查询与曲库管理体验。</p></blockquote><br><h2 id="✨-核心特性" tabindex="-1">✨ 核心特性 <a class="header-anchor" href="#✨-核心特性" aria-label="Permalink to &quot;✨ 核心特性&quot;">​</a></h2><ul><li><strong>现代化交互 UI</strong>：六宫格清晰布局，玩家名片全景展示（Rating、段位、阶级、底板、头像、称号跑马灯）</li><li><strong>极速曲库与智能筛选</strong>：支持定数范围、游戏版本、乐曲分类三重联合筛选，服务端定时拉取官方数据</li><li><strong>成绩同步与追踪</strong>：一键同步最新玩家状态，直观展示最新游玩成绩、单曲达成率与评级</li><li><strong>极致的安全架构</strong>：客户端完全脱敏，不包含任何第三方开发者 API Key；服务端每日自动清洗落雪数据</li></ul><br><h2 id="🏗️-架构说明" tabindex="-1">🏗️ 架构说明 <a class="header-anchor" href="#🏗️-架构说明" aria-label="Permalink to &quot;🏗️ 架构说明&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">组件</th><th style="text-align:left;">技术栈</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Android 客户端</strong></td><td style="text-align:left;">Kotlin, RecyclerView, CardView, Coroutines, OkHttp, Glide</td></tr><tr><td style="text-align:left;"><strong>后端服务</strong></td><td style="text-align:left;">Python FastAPI, Uvicorn, 数据清洗守护进程</td></tr></tbody></table><br><div style="text-align:center;margin:30px 0;"><a href="https://github.com/HX-Wrdzgzs/Mizuki-Sync-Android" target="_blank" class="mzk-button"> 📦 查看 GitHub 仓库 </a></div>',11)])])}const k=i(r,[["render",o]]);export{g as __pageData,k as default};
